return [
  {
    json: {
      transcript_source_url: 'https://www.youtube.com/watch?v=dQw4w9WgXcQ',
      source_name: 'Video Transcript API smoke',
      source_type: 'transcript',
      media_type: 'video',
      use_speaker_recognition: false,
      published_at: new Date().toISOString(),
      obsidian_inbox_dir: '00_Inbox/AI_Information_Processor'
    }
  }
];

const sourceUrl = String($json.transcript_source_url || $json.url || '').trim();
if (!sourceUrl) {
  throw new Error('transcript_source_url is required for 04_video_transcript_ingest');
}

const baseUrl = String($env.VIDEO_TRANSCRIPT_BASE_URL || '').trim().replace(/\/+$/, '');
const apiKey = String($env.VIDEO_TRANSCRIPT_API_KEY || '').trim();
if (!baseUrl) {
  throw new Error('VIDEO_TRANSCRIPT_BASE_URL is required for 04_video_transcript_ingest');
}
if (!apiKey) {
  throw new Error('VIDEO_TRANSCRIPT_API_KEY is required for 04_video_transcript_ingest');
}

const metadataOverride = {};
for (const [sourceKey, targetKey] of [
  ['title', 'title'],
  ['author', 'author'],
  ['description', 'description']
]) {
  const value = String($json[sourceKey] || '').trim();
  if (value) {
    metadataOverride[targetKey] = value;
  }
}

const requestBody = {
  url: sourceUrl,
  use_speaker_recognition: Boolean($json.use_speaker_recognition),
};

const downloadUrl = String($json.download_url || '').trim();
if (downloadUrl) {
  requestBody.download_url = downloadUrl;
}

const wechatWebhook = String($json.wechat_webhook || '').trim();
if (wechatWebhook) {
  requestBody.wechat_webhook = wechatWebhook;
}

if (Object.keys(metadataOverride).length) {
  requestBody.metadata_override = metadataOverride;
}

return {
  json: {
    ...$json,
    transcript_source_url: sourceUrl,
    transcript_api: {
      base_url: baseUrl,
      api_key: apiKey,
      submit_url: `${baseUrl}/api/transcribe`,
      request_body: requestBody,
      poll_interval_ms: Math.max(1000, Number($json.poll_interval_ms || 3000)),
      max_polls: Math.max(1, Number($json.max_polls || 40))
    }
  }
};

const requestItem = $('Build Transcript API Request').item.json || {};
const submitResponse = $json || {};
const transcriptApi = requestItem.transcript_api || {};
const baseUrl = String(transcriptApi.base_url || '').replace(/\/+$/, '');
const apiKey = String(transcriptApi.api_key || '').trim();
const taskId = String(submitResponse?.data?.task_id || '').trim();
const viewToken = String(submitResponse?.data?.view_token || '').trim();

if (!baseUrl || !apiKey) {
  throw new Error('Transcript API connection info is missing after submission');
}
if (!taskId || !viewToken) {
  throw new Error(`Transcript API submit response missing task_id/view_token: ${JSON.stringify(submitResponse)}`);
}

return {
  json: {
    ...requestItem,
    submit_response: submitResponse,
    upstream_task_id: taskId,
    upstream_view_token: viewToken,
    poll_attempt: 0,
    poll_state: 'pending',
    task_status_url: `${baseUrl}/api/task/${encodeURIComponent(taskId)}`,
    transcript_exports: {
      calibrated: `${baseUrl}/view/${viewToken}?raw=calibrated`,
      transcript: `${baseUrl}/view/${viewToken}?raw=transcript`,
      summary: `${baseUrl}/view/${viewToken}?raw=summary`
    }
  }
};

if (!String($json.task_status_url || '').trim()) {
  throw new Error('task_status_url is required before polling Transcript API task status');
}

return {
  json: {
    ...$json
  }
};

const context = $('Prepare Transcript Task Status Request').item.json || {};
const taskStatus = $json || {};
const maxPolls = Math.max(1, Number(context.transcript_api?.max_polls || 40));
const nextAttempt = Number(context.poll_attempt || 0) + 1;
const responseCode = Number(taskStatus.code || 0);

if (!Number.isFinite(responseCode)) {
  throw new Error(`Transcript API task status returned a non-numeric code: ${JSON.stringify(taskStatus)}`);
}

if (responseCode === 202) {
  if (nextAttempt >= maxPolls) {
    throw new Error(`Transcript API task ${context.upstream_task_id || 'unknown'} did not finish within ${maxPolls} polls`);
  }

  return {
    json: {
      ...context,
      poll_attempt: nextAttempt,
      poll_state: 'pending',
      transcript_status: String(taskStatus.message || '').trim()
    }
  };
}

if (responseCode >= 500) {
  throw new Error(`Transcript API task ${context.upstream_task_id || 'unknown'} failed: ${taskStatus.message || 'unknown error'}`);
}

const taskData = taskStatus.data && typeof taskStatus.data === 'object' ? taskStatus.data : {};
const transcriptText = String(taskData.transcript || '').trim();
if (!transcriptText) {
  throw new Error(`Transcript API task ${context.upstream_task_id || 'unknown'} completed without transcript text`);
}

return {
  json: {
    ...context,
    poll_attempt: nextAttempt,
    poll_state: 'completed',
    upstream_summary: String(context.upstream_summary || '').trim(),
    canonical_url: String(context.canonical_url || context.transcript_source_url || '').trim(),
    original_id: String(context.original_id || `video-transcript:${context.upstream_view_token || 'unknown'}`).trim(),
    title: String(taskData.video_title || context.title || 'untitled transcript item').trim() || 'untitled transcript item',
    author: String(taskData.author || context.author || '').trim(),
    published_at: context.published_at || new Date().toISOString(),
    transcript_text: transcriptText,
    transcript_status: String(taskStatus.message || '').trim(),
    original_item: {
      request: context.transcript_api?.request_body || {},
      submit_response: context.submit_response || {},
      task_status: taskStatus
    }
  }
};

const delayMs = Math.max(1000, Number($json.transcript_api?.poll_interval_ms || 3000));
await new Promise((resolve) => setTimeout(resolve, delayMs));
return {
  json: {
    ...$json
  }
};

const transcriptText = String($json.transcript_text || $json.calibrated_transcript || '').trim();
if (!transcriptText) {
  throw new Error('Resolved transcript payload is missing transcript_text');
}

const obsidianInboxDir = String($json.obsidian_inbox_dir || $env.OBSIDIAN_INBOX_DIR || '00_Inbox/AI_Information_Processor').trim() || '00_Inbox/AI_Information_Processor';

return {
  json: {
    source_type: String($json.source_type || 'transcript').trim() || 'transcript',
    source_name: String($json.source_name || 'video-transcript-api').trim() || 'video-transcript-api',
    canonical_url: String($json.canonical_url || $json.transcript_source_url || '').trim(),
    original_id: String($json.original_id || '').trim(),
    title: String($json.title || 'untitled').trim() || 'untitled',
    author: String($json.author || '').trim(),
    published_at: $json.published_at || new Date().toISOString(),
    media_type: String($json.media_type || 'video').trim() || 'video',
    raw_html: '',
    raw_text: transcriptText,
    obsidian_inbox_dir: obsidianInboxDir,
    extra_tags: ['transcript'],
    upstream_task_id: String($json.upstream_task_id || '').trim(),
    upstream_view_token: String($json.upstream_view_token || '').trim(),
    upstream_summary: String($json.upstream_summary || '').trim(),
    original_item: $json.original_item ?? $json
  }
};
